#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005

// Define the structure for a tree edge
typedef struct Edge {
    int u, v, c;
} Edge;

// Define the structure for a tree
typedef struct Tree {
    int n;
    Edge *edges;
} Tree;

// Function to perform DFS and count the number of black and white edges
void dfs(int u, int p, Tree *tree, int *black, int *white) {
    for (int i = 0; i < tree->n - 1; i++) {
        if (tree->edges[i].u == u && tree->edges[i].v != p) {
            if (tree->edges[i].c == 0) {
                (*black)++;
            } else {
                (*white)++;
            }
            dfs(tree->edges[i].v, u, tree, black, white);
        } else if (tree->edges[i].v == u && tree->edges[i].u != p) {
            if (tree->edges[i].c == 0) {
                (*black)++;
            } else {
                (*white)++;
            }
            dfs(tree->edges[i].u, u, tree, black, white);
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Tree tree;
        tree.n = N;
        tree.edges = (Edge *)malloc((N - 1) * sizeof(Edge));
        for (int i = 0; i < N - 1; i++) {
            scanf("%d %d %d", &tree.edges[i].u, &tree.edges[i].v, &tree.edges[i].c);
        }
        int black = 0, white = 0;
        dfs(1, -1, &tree, &black, &white);
        if ((black + white) % 2 == 0) {
            if(black % 2 == 0) printf("Ksen Ksen\n");
            else printf("Chef Ksen\n");
        } else {
            if(black % 2 == 0) printf("Chef Chef\n");
            else printf("Chef Ksen\n");
        }
        free(tree.edges);
    }
    return 0;
}

