import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Main {
    static class Edge {
        int u, v, c;

        public Edge(int u, int v, int c) {
            this.u = u;
            this.v = v;
            this.c = c;
        }
    }

    static class Tree {
        int n;
        List<Edge> edges;

        public Tree(int n) {
            this.n = n;
            this.edges = new ArrayList<>();
        }
    }

    public static void dfs(int u, int p, Tree tree, int[] count) {
        for (Edge edge : tree.edges) {
            if (edge.u == u && edge.v != p) {
                if (edge.c == 0) {
                    count[0]++;
                } else {
                    count[1]++;
                }
                dfs(edge.v, u, tree, count);
            } else if (edge.v == u && edge.u != p) {
                if (edge.c == 0) {
                    count[0]++;
                } else {
                    count[1]++;
                }
                dfs(edge.u, u, tree, count);
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Tree tree = new Tree(N);
            for (int i = 0; i < N - 1; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                int c = scanner.nextInt();
                tree.edges.add(new Edge(u, v, c));
            }
            int[] count = new int[2];
            dfs(1, -1, tree, count);
